parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "userIdea": {
      "type": "string",
      "description": "Normalized base object (lowercase singular) applied to every idea."
    },
    "ideas": {
      "type": "array",
      "description": "Exactly 12 unique AISMR-ready concepts in Title Case descriptor + singular object format.",
      "items": {
        "type": "object",
        "properties": {
          "idea": {
            "type": "string",
            "description": "Title Case descriptor + singular object (two words, descriptor is one word)."
          },
          "vibe": {
            "type": "string",
            "description": "2-4 sentence explanation covering emotion, hook, texture, feasibility, replay value, and environment potential."
          }
        },
        "required": [
          "idea",
          "vibe"
        ],
        "additionalProperties": false
      },
      "minItems": 12,
      "maxItems": 12
    }
  },
  "required": [
    "userIdea",
    "ideas"
  ],
  "additionalProperties": false
}

parameters.jsCode:
const candidates = [$json.sessionId, $json.conversationSessionId, $json.mcpSessionId];
const existing = candidates.find((value) => typeof value === 'string' && value.trim().length > 0) ?? null;
const payload = { ...$json };
if (existing) {
  const sessionId = existing.trim();
  payload.sessionId = sessionId;
  payload.conversationSessionId = sessionId;
}
return { json: payload };

const existingSessionId = typeof $json.sessionId === 'string' && $json.sessionId.trim().length > 0 ? $json.sessionId.trim() : null;
const rawOutput = $json.output ?? $json.result ?? $json;
let content = typeof rawOutput === 'string' ? rawOutput : JSON.stringify(rawOutput, null, 2);
if (!content || content.trim().length === 0) {
  content = JSON.stringify($json, null, 2);
}
const normalized = content.length > 4000 ? `${content.slice(0, 3997)}…` : content;
const metadata = {
  personaId: $json.personaId ?? null,
  projectId: $json.projectId ?? null,
  chatInput: $json.chatInput ?? null,
  workflow: $json.workflow ?? 'mylo-mcp-bot',
  outputSchema: $json.outputSchema ?? null,
};
const args = {
  role: 'assistant',
  content: normalized,
  metadata,
  tags: ['agent-response', 'mylo-mcp-bot'],
};
if (existingSessionId) {
  args.sessionId = existingSessionId;
}
const requestId = `store-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
return {
  json: {
    ...$json,
    conversationStoreRequest: {
      jsonrpc: '2.0',
      id: requestId,
      method: 'tools/call',
      params: {
        name: 'conversation_store',
        arguments: args,
      },
    },
  },
};

function parseStructured(value) {
  if (value == null) return null;
  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (!trimmed) {
      return null;
    }
    try {
      return JSON.parse(trimmed);
    } catch (error) {
      return null;
    }
  }
  if (typeof value === 'object') {
    return value;
  }
  return null;
}

const personaId = $json.personaId ?? null;
const projectId = $json.projectId ?? null;
const sessionCandidates = [$json.sessionId, $json.conversationSessionId, $json.mcpSessionId];
const sessionId = sessionCandidates.find((value) => typeof value === 'string' && value.trim().length > 0) ?? null;
const chatInput = typeof $json.chatInput === 'string' ? $json.chatInput.trim() : '';

const primaryOutput = $json.output ?? $json.result ?? $json.response ?? $json.data ?? null;
let structured = parseStructured(primaryOutput);
if (!structured && typeof $json.parsedOutput === 'object') {
  structured = $json.parsedOutput;
}

const ideas = Array.isArray(structured?.ideas) ? structured.ideas : Array.isArray($json.ideas) ? $json.ideas : [];
const ideaSummaries = [];
const ideaTitles = [];

for (const idea of ideas) {
  if (!idea || typeof idea !== 'object') continue;
  const title = typeof idea.idea === 'string' && idea.idea.trim().length > 0
    ? idea.idea.trim()
    : typeof idea.title === 'string' && idea.title.trim().length > 0
      ? idea.title.trim()
      : null;
  const vibe = typeof idea.vibe === 'string' ? idea.vibe.trim() : typeof idea.description === 'string' ? idea.description.trim() : '';
  if (title) {
    ideaTitles.push(title);
  }
  const line = title ? `- ${title}${vibe ? `: ${vibe}` : ''}` : vibe ? `- ${vibe}` : null;
  if (line) {
    ideaSummaries.push(line);
  }
}

const memoryCandidates = [];
const nowIso = new Date().toISOString();
const isoDate = nowIso.slice(0, 10);

if (projectId && ideaSummaries.length > 0) {
  const titleParts = ['Decision'];
  if (projectId) {
    titleParts.push(projectId);
  }
  if (personaId) {
    titleParts.push(personaId);
  }
  titleParts.push(isoDate);
  const decisionTitle = titleParts.join(' · ');

  const contentSections = [
    `Project: ${projectId}`,
    personaId ? `Persona: ${personaId}` : null,
    `Generated ${ideaSummaries.length} concept${ideaSummaries.length === 1 ? '' : 's'} via Mylo MCP Bot.`,
    '',
    'Key Concepts:',
    ...ideaSummaries.slice(0, 8),
  ].filter(Boolean);

  memoryCandidates.push({
    memoryType: 'project',
    title: decisionTitle,
    content: contentSections.join('
'),
    tags: [
      'decision',
      `project:${projectId}`,
      personaId ? `persona:${personaId}` : null,
      'mylo-mcp-bot',
    ].filter(Boolean),
    metadata: {
      personaId,
      projectId,
      capturedAt: nowIso,
      summaryIdeas: ideaTitles.slice(0, 12),
      reviewStatus: 'pending_review',
      requiresHumanReview: true,
    },
    confidence: 0.7,
    visibility: 'team',
    source: 'agent',
  });

  const semanticTitleParts = ['AISMR Concepts', isoDate];
  if (projectId) {
    semanticTitleParts.splice(1, 0, projectId);
  }
  const semanticTitle = semanticTitleParts.join(' · ');

  const semanticContent = [
    `Highlights captured on ${isoDate}.`,
    '',
    ...ideaSummaries.slice(0, 6),
  ].join('
');

  memoryCandidates.push({
    memoryType: 'semantic',
    title: semanticTitle,
    content: semanticContent,
    tags: [
      'semantic-note',
      'mylo-mcp-bot',
      projectId ? `project:${projectId}` : null,
      personaId ? `persona:${personaId}` : null,
    ].filter(Boolean),
    metadata: {
      personaId,
      projectId,
      capturedAt: nowIso,
      summaryIdeas: ideaTitles.slice(0, 12),
      reviewStatus: 'pending_review',
      requiresHumanReview: false,
    },
    confidence: 0.6,
    visibility: 'team',
    source: 'agent',
  });
}

if (chatInput && sessionId) {
  memoryCandidates.push({
    memoryType: 'episodic',
    title: `User Preference · ${isoDate}`,
    content: `User request excerpt: "${chatInput.slice(0, 400)}"${chatInput.length > 400 ? '…' : ''}`,
    tags: [
      'user-preference',
      'mylo-mcp-bot',
      sessionId ? `session:${sessionId.slice(0, 8)}` : null,
    ].filter(Boolean),
    metadata: {
      personaId,
      projectId,
      capturedAt: nowIso,
      reviewStatus: 'pending_review',
      requiresHumanReview: true,
    },
    confidence: 0.5,
    visibility: 'private',
    source: 'agent',
    sessionId,
  });
}

return [
  {
    json: {
      ...$json,
      structuredOutput: structured,
      memoryCandidates,
      sessionId,
      generatedAt: nowIso,
    },
  },
];

const memoryCandidates = Array.isArray($json.memoryCandidates) ? $json.memoryCandidates : [];

if (memoryCandidates.length === 0) {
  return [];
}

function extractStructuredContent(payload) {
  if (!payload || typeof payload !== 'object') {
    return null;
  }
  if (payload.structuredContent && typeof payload.structuredContent === 'object') {
    return payload.structuredContent;
  }
  if (payload.result && typeof payload.result === 'object') {
    return extractStructuredContent(payload.result);
  }
  if (payload.data && typeof payload.data === 'object') {
    return extractStructuredContent(payload.data);
  }
  return null;
}

const conversationResponse = $json.result ?? $json.response ?? $json;
const structuredContent = extractStructuredContent(conversationResponse) ?? {};
const conversationChunkId = structuredContent.chunkId ?? structuredContent.chunkID ?? structuredContent.chunk_id ?? null;
const sessionId = structuredContent.sessionId ?? structuredContent.sessionID ?? structuredContent.session_id ?? $json.sessionId ?? null;

const actor = {
  type: 'agent',
  id: 'mylo-mcp-bot',
  scopes: ['runtime-memory'],
};

const results = [];

for (const candidate of memoryCandidates) {
  if (!candidate || typeof candidate !== 'object') continue;

  const args = {
    ...candidate,
    actor,
  };

  if (args.memoryType === 'episodic' && !args.sessionId && sessionId) {
    args.sessionId = sessionId;
  }

  const existingRelated = Array.isArray(args.relatedChunkIds) ? args.relatedChunkIds.slice() : [];
  if (conversationChunkId && !existingRelated.includes(conversationChunkId)) {
    existingRelated.push(conversationChunkId);
  }
  if (existingRelated.length > 0) {
    args.relatedChunkIds = existingRelated;
  }

  const metadata = {
    ...(args.metadata ?? {}),
    conversationChunkId,
    workflow: 'mylo-mcp-bot',
  };
  if (!metadata.reviewStatus) {
    metadata.reviewStatus = 'pending_review';
  }
  args.metadata = metadata;

  if (!Array.isArray(args.tags)) {
    args.tags = [];
  }
  if (!args.tags.includes('needs-review')) {
    args.tags.push('needs-review');
  }

  const rpcPayload = {
    jsonrpc: '2.0',
    id: `memory-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    method: 'tools/call',
    params: {
      name: 'memory_add',
      arguments: args,
      options: {
        timeout: 15000,
      },
    },
  };

  results.push({
    rpcPayload,
    memoryType: args.memoryType,
    title: args.title ?? null,
  });
}

return results.map((entry) => ({ json: entry }));
